      // default slate-700
      "oklch(37.2% 0.044 257.287)",
    ],
    ["--brand-secondary", "oklch(100% 0 0)"],
  ]);
  colorMap.forEach((value, key) => {
    document.documentElement.style.setProperty(key, value);
  });
};

const required =
  (fieldName: string) =>
  ({ value }: { value: string }) =>
    !value ? `${fieldName} is required` : undefined;

const emailRegex =
  /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;

const validEmail = ({ value }: { value: string }) => {
  if (!value) {
    return "Email is required";
  }

  return emailRegex.test(value)
    ? undefined
    : "Please enter a valid email address";
};

const possiblePhoneNumber = ({ value }: { value: string }) => {
  if (!value) {
    return "Phone is required";
  }

  return RPNInput.isPossiblePhoneNumber(value as RPNInput.Value)
    ? undefined
    : "Please enter a valid phone number";
};

const isValidCallbackUrl = (callbackUrl: unknown): callbackUrl is string => {
  if (typeof callbackUrl !== "string") {
    return false;
  }

  const trimmed = callbackUrl.trim();
  if (!trimmed) {
    return false;
  }

  if (trimmed.startsWith("/")) {
    // Reject protocol-relative URLs like //example.com.
    return !trimmed.startsWith("//");
  }

  try {
    const parsedUrl = new URL(trimmed);
    return parsedUrl.protocol === "http:" || parsedUrl.protocol === "https:";
  } catch {
    return false;
  }
};

