                (value) => value.trim().length > 0,
              );

              return (
                <Button
                  type="submit"
                  className={`w-full ${
                    !isPending && !isFormComplete ? "opacity-50" : ""
                  }`}
                  size="lg"
                  disabled={isPending}
                  aria-disabled={!isPending && !isFormComplete}
                  name="submit"
                >
                  Submit
                </Button>
